import {
  forwardRef,
  useRef,
  useCallback,
  useId,
  useMemo,
  type HTMLAttributes,
} from "react";
import { clsx } from "clsx";
import * as styles from "./OTPFieldset.css";
import type { OTPFieldsetSize } from "./OTPFieldset.config";
import {
  DEFAULT_OTP_FIELDSET_SIZE,
  DEFAULT_OTP_FIELDSET_LENGTH,
} from "./OTPFieldset.config";
import { useOTPFieldsetKeyboard } from "./hooks/useOTPFieldsetKeyboard";
import { useTranslations, interpolate } from "../hooks/useTranslations";
import translations from "./i18n.json";
import { Legend } from "../Legend";
import type { LegendProps } from "../Legend";
import { Hint } from "../Hint";
import type { HintCustomProps } from "../Hint";
import { ValidationMessage } from "../ValidationMessage";
import type {
  ValidationMessageValidProps,
  ValidationMessageInvalidProps,
} from "../ValidationMessage";
import { Input } from "../Input";
import { SIZE_TO_INPUT_SIZE } from "./OTPFieldset.config";
import {
  resolveCharacterConfig,
  processString,
  parseValueToArray,
  joinArrayToValue,
  cleanValue,
  isComplete,
  type CharacterConfigProp,
} from "./utils";

export type OTPFieldsetLegend = Omit<LegendProps, "asChild">;

export type OTPFieldsetHint = HintCustomProps;

export type OTPFieldsetValidationMessage =
  | ValidationMessageValidProps
  | ValidationMessageInvalidProps;

interface OTPFieldsetCustomProps {
  /**
   * The current value of the OTP input
   */
  value: string;

  /**
   * Callback fired when the OTP value changes
   */
  onChange: (value: string) => void;

  /**
   * Callback fired when all characters have been entered.
   * Receives the complete value (without placeholder characters).
   * Useful for auto-submitting forms or triggering validation.
   */
  onComplete?: (value: string) => void;

  /**
   * The number of character inputs
   * @default 6
   */
  length?: number;

  /**
   * The size of the input cells
   * @default 'md'
   */
  size?: OTPFieldsetSize;

  /**
   * The validation message configuration.
   * When provided with `variant: "invalid"`, applies invalid styling to inputs.
   */
  validationMessage?: OTPFieldsetValidationMessage;

  /**
   * Whether the input is disabled
   */
  disabled?: boolean;

  /**
   * The name attribute for the hidden input (for form submission)
   */
  name?: string;

  /**
   * The legend configuration (acts as the accessible name for the OTP input group).
   * If not provided, use `aria-labelledby` to reference an external label element.
   */
  legend?: OTPFieldsetLegend;

  /**
   * The hint configuration (displayed below the legend)
   */
  hint?: OTPFieldsetHint;

  /**
   * Configuration for character filtering and transformation.
   * @default { whitelistedChars: "[0-9]", transform: "none" }
   * @example { whitelistedChars: "[a-zA-Z0-9]" } // alphanumeric only
   * @example { whitelistedChars: "[a-zA-Z0-9]", transform: "uppercase" } // alphanumeric, uppercase
   * @example { whitelistedChars: "*" } // allow all characters
   */
  characterConfig?: CharacterConfigProp;
}

export interface OTPFieldsetProps
  extends
    Omit<HTMLAttributes<HTMLFieldSetElement>, keyof OTPFieldsetCustomProps>,
    OTPFieldsetCustomProps {}

export const OTPFieldset = forwardRef<HTMLFieldSetElement, OTPFieldsetProps>(
  (
    {
      value,
      onChange,
      onComplete,
      length = DEFAULT_OTP_FIELDSET_LENGTH,
      size = DEFAULT_OTP_FIELDSET_SIZE,
      validationMessage,
      disabled,
      name,
      legend,
      hint,
      characterConfig: characterConfigProp,
      className,
      ...props
    },
    ref
  ) => {
    const inputRefs = useRef<(HTMLInputElement | null)[]>([]);
    const t = useTranslations(translations);
    const uniqueId = useId();

    // Generate IDs for accessibility
    const hintId = hint ? `${uniqueId}-hint` : undefined;
    const validationMessageId = validationMessage
      ? `${uniqueId}-validation`
      : undefined;

    // Build aria-describedby from hint and validation message IDs
    const describedByIds = [hintId, validationMessageId].filter(
      Boolean
    ) as string[];
    const ariaDescribedBy =
      describedByIds.length > 0 ? describedByIds.join(" ") : undefined;

    // Resolve character config with defaults
    const characterConfig = useMemo(
      () => resolveCharacterConfig(characterConfigProp),
      [characterConfigProp]
    );

    // Filter out disallowed characters and apply transformations to the value before parsing
    const processedValue = useMemo(
      () => processString(value, characterConfig),
      [value, characterConfig]
    );

    const values = parseValueToArray(processedValue, length);

    // Handle value changes
    const handleValuesChange = useCallback(
      (newValues: string[]) => {
        const newValue = joinArrayToValue(newValues);
        onChange(newValue);

        // Call onComplete when all positions are filled with actual characters
        if (onComplete && isComplete(newValue, length)) {
          onComplete(cleanValue(newValue));
        }
      },
      [onChange, onComplete, length]
    );

    // Determine inputMode based on character config
    // Use "numeric" for numeric-only patterns to show a numeric keyboard on mobile
    const inputMode = useMemo(() => {
      const numericPatterns = ["[0-9]", "[0-9]+", "\\d", "\\d+"];
      return numericPatterns.includes(characterConfig.whitelistedChars)
        ? "numeric"
        : "text";
    }, [characterConfig.whitelistedChars]);

    // Keyboard handling
    const { handleKeyDown, handleInput, handlePaste } = useOTPFieldsetKeyboard({
      inputRefs,
      values,
      onChange: handleValuesChange,
      length,
      disabled: disabled ?? false,
      characterConfig,
    });

    // Focus the first input when clicking the legend
    const handleLegendClick = useCallback(() => {
      inputRefs.current[0]?.focus();
    }, []);

    return (
      <fieldset
        ref={ref}
        className={clsx(styles.fieldset, className)}
        {...(ariaDescribedBy !== undefined && {
          "aria-describedby": ariaDescribedBy,
        })}
        {...props}
      >
        {/* Legend and hint for accessible labeling */}
        {(legend || hint) && (
          <div className={styles.legendHintStack}>
            {legend && (
              <Legend
                {...legend}
                onClick={handleLegendClick}
                className={clsx(styles.clickableLegend, legend.className)}
              >
                {legend.children}
              </Legend>
            )}
            {hint && (
              <Hint id={hintId} {...hint}>
                {hint.children}
              </Hint>
            )}
          </div>
        )}

        {/* Container for the OTP input cells */}
        <div className={styles.container({ size })}>
          {/* Hidden input for form submission (uses cleaned value without placeholders) */}
          {name && (
            <input
              type="hidden"
              name={name}
              // Combined value for the hidden form input
              value={cleanValue(joinArrayToValue(values))}
              aria-hidden="true"
            />
          )}

          {values.map((cellValue, index) => {
            const inputId = `${uniqueId}-otp-${index}`;
            const cellLabel = interpolate(t.digitLabel, {
              current: index + 1,
              total: length,
            });

            return (
              <Input
                key={inputId}
                ref={(el) => {
                  inputRefs.current[index] = el;
                }}
                id={inputId}
                type="text"
                inputMode={inputMode}
                autoComplete={index === 0 ? "one-time-code" : "off"}
                maxLength={1}
                value={cellValue}
                disabled={disabled}
                aria-label={cellLabel}
                // Map OTPFieldset size to Input size (Input doesn't support "lg")
                size={SIZE_TO_INPUT_SIZE[size]}
                // Derive validation state from validationMessage
                validation={validationMessage?.variant}
                className={styles.inputCell({ size })}
                onKeyDown={(e) => handleKeyDown(index, e)}
                onChange={(e) => handleInput(index, e)}
                onPaste={(e) => handlePaste(index, e)}
              />
            );
          })}
        </div>

        {/* Validation message */}
        {validationMessage && (
          <ValidationMessage id={validationMessageId} {...validationMessage} />
        )}
      </fieldset>
    );
  }
);

OTPFieldset.displayName = "OTPFieldset";
