import { useCallback, type RefObject, type ClipboardEvent } from "react";
import type { OTPFieldsetCharacterConfig } from "../OTPFieldset.config";
import { processCharacter, processString } from "../utils";

export interface UseOTPFieldsetKeyboardOptions {
  /** Array of refs to the individual input elements */
  inputRefs: RefObject<(HTMLInputElement | null)[]>;
  /** Current values for each input */
  values: string[];
  /** Callback when values change */
  onChange: (values: string[]) => void;
  /** Number of input cells */
  length: number;
  /** Whether the inputs are disabled */
  disabled?: boolean;
  /** Character filtering and transformation config */
  characterConfig: OTPFieldsetCharacterConfig;
}

export interface UseOTPFieldsetKeyboardReturn {
  /** Handle keydown events on individual inputs */
  handleKeyDown: (
    index: number,
    event: React.KeyboardEvent<HTMLInputElement>
  ) => void;
  /** Handle input change events */
  handleInput: (
    index: number,
    event: React.ChangeEvent<HTMLInputElement>
  ) => void;
  /** Handle paste events */
  handlePaste: (index: number, event: ClipboardEvent<HTMLInputElement>) => void;
}

/**
 * Hook that manages keyboard interactions for OTP input cells.
 *
 * Handles:
 * - Character input with auto-advance to next cell
 * - Backspace: delete current character, move to previous if empty
 * - Delete: delete current character, stay in place
 * - Arrow Left/Right: navigate between cells
 * - Paste: distribute pasted characters across cells
 */
export function useOTPFieldsetKeyboard({
  inputRefs,
  values,
  onChange,
  length,
  disabled,
  characterConfig,
}: UseOTPFieldsetKeyboardOptions): UseOTPFieldsetKeyboardReturn {
  const focusInput = useCallback(
    (index: number) => {
      const clampedIndex = Math.max(0, Math.min(index, length - 1));
      inputRefs.current?.[clampedIndex]?.focus();
    },
    [inputRefs, length]
  );

  const updateValue = useCallback(
    (index: number, value: string) => {
      const newValues = [...values];
      // Only take the first character and process it
      const char = value.slice(0, 1);
      const processedChar = char ? processCharacter(char, characterConfig) : "";
      // Only update if the character is allowed (not filtered out)
      if (processedChar !== null) {
        newValues[index] = processedChar;
        onChange(newValues);
        return true;
      }
      return false;
    },
    [values, onChange, characterConfig]
  );

  const handleKeyDown = useCallback(
    (index: number, event: React.KeyboardEvent<HTMLInputElement>) => {
      if (disabled) return;

      const { key } = event;

      switch (key) {
        case "Backspace": {
          event.preventDefault();
          const currentValue = values[index] ?? "";
          if (currentValue) {
            // Delete current character
            updateValue(index, "");
          } else if (index > 0) {
            // Move to previous input and delete its character
            updateValue(index - 1, "");
            focusInput(index - 1);
          }
          break;
        }

        case "Delete": {
          event.preventDefault();
          // Delete current character, stay in place
          updateValue(index, "");
          break;
        }

        case "ArrowLeft": {
          event.preventDefault();
          if (index > 0) {
            focusInput(index - 1);
          }
          break;
        }

        case "ArrowRight": {
          event.preventDefault();
          if (index < length - 1) {
            focusInput(index + 1);
          }
          break;
        }

        // Let Tab/Shift+Tab work naturally for accessibility
        case "Tab":
          break;

        default:
          // Handle single printable characters
          if (
            key.length === 1 &&
            !event.ctrlKey &&
            !event.metaKey &&
            !event.altKey
          ) {
            const currentValue = values[index] ?? "";
            // If cell already has a value, we need to handle replacement here
            // because maxLength={1} prevents the change event from firing
            if (currentValue) {
              event.preventDefault();
              const updated = updateValue(index, key);
              // Auto-advance to next input only if the character was accepted
              if (updated && index < length - 1) {
                focusInput(index + 1);
              }
            } else {
              // If cell is empty, check if the character will be allowed
              // If not, prevent the default behavior so nothing appears
              const processedChar = processCharacter(key, characterConfig);
              if (processedChar === null) {
                event.preventDefault();
              }
            }
          }
          break;
      }
    },
    [disabled, values, updateValue, focusInput, length, characterConfig]
  );

  const handleInput = useCallback(
    (index: number, event: React.ChangeEvent<HTMLInputElement>) => {
      if (disabled) return;

      const inputValue = event.target.value;

      // Handle case where browser autofill inserts multiple characters
      if (inputValue.length > 1) {
        // Process and distribute characters across inputs
        const processedChars = processString(inputValue, characterConfig);
        if (processedChars.length === 0) return;

        const chars = processedChars.split("");
        const newValues = [...values];

        chars.forEach((char, charIndex) => {
          const targetIndex = index + charIndex;
          if (targetIndex < length) {
            newValues[targetIndex] = char;
          }
        });

        onChange(newValues);

        // Focus the next empty input or the last filled one
        const nextEmptyIndex = newValues.findIndex((v, i) => i >= index && !v);
        const focusIndex =
          nextEmptyIndex !== -1
            ? nextEmptyIndex
            : Math.min(index + chars.length, length - 1);
        focusInput(focusIndex);
        return;
      }

      // Single character input
      if (inputValue.length === 1) {
        const updated = updateValue(index, inputValue);
        // Auto-advance to next input only if the character was accepted
        if (updated && index < length - 1) {
          focusInput(index + 1);
        }
      } else if (inputValue.length === 0) {
        // Input was cleared (shouldn't happen normally, but handle it)
        updateValue(index, "");
      }
    },
    [
      disabled,
      values,
      onChange,
      length,
      updateValue,
      focusInput,
      characterConfig,
    ]
  );

  const handlePaste = useCallback(
    (index: number, event: ClipboardEvent<HTMLInputElement>) => {
      if (disabled) return;

      event.preventDefault();
      const pastedText = event.clipboardData.getData("text");

      if (!pastedText) return;

      // Process and distribute pasted characters starting from current index
      const processedText = processString(pastedText, characterConfig);
      if (processedText.length === 0) return;

      const chars = processedText.split("");
      const newValues = [...values];

      chars.forEach((char, charIndex) => {
        const targetIndex = index + charIndex;
        if (targetIndex < length) {
          newValues[targetIndex] = char;
        }
      });

      onChange(newValues);

      // Focus the next empty input or the last filled one
      const filledCount = Math.min(chars.length, length - index);
      const nextIndex = index + filledCount;
      const focusIndex = nextIndex < length ? nextIndex : length - 1;
      focusInput(focusIndex);
    },
    [disabled, values, onChange, length, focusInput, characterConfig]
  );

  return {
    handleKeyDown,
    handleInput,
    handlePaste,
  };
}
